// ValidateCreateMcpSlugRequestBody runs the validations defined on
// CreateMcpSlugRequestBody
func ValidateCreateMcpSlugRequestBody(body *CreateMcpSlugRequestBody) (err error) {
	if body.McpFrontendID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("mcp_frontend_id", "body"))
	}
	if body.Slug == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("slug", "body"))
	}
	if body.CustomDomainID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.custom_domain_id", *body.CustomDomainID, goa.FormatUUID))
	}
	if body.McpFrontendID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.mcp_frontend_id", *body.McpFrontendID, goa.FormatUUID))
	}
	if body.Slug != nil {
		err = goa.MergeErrors(err, goa.ValidatePattern("body.slug", *body.Slug, "^[a-z0-9_-]{1,128}$"))
	}
	if body.Slug != nil {
		if utf8.RuneCountInString(*body.Slug) > 128 {
			err = goa.MergeErrors(err, goa.InvalidLengthError("body.slug", *body.Slug, utf8.RuneCountInString(*body.Slug), 128, false))
		}
	}
	return
}

